//! CCH weights format - customized edge weights for CCH
//!
//! Stores per-mode edge weights for both UP and DOWN edges.
//! Generated by Step 8 (customization).
//!
//! # Zero-Copy Reads (#147)
//!
//! For Belgium-scale data, four modes × {time, dist} weights total
//! ~6 GB on disk. Eagerly copying these into `Vec<u32>` doubles the
//! resident memory of an mmap-backed server (mmap pages + Vec heap).
//! `read_from_bytes_zero_copy` returns the same struct shape but with
//! `Cow::Borrowed` slices over the mmap, so the kernel demand-pages
//! only the bytes we touch and the heap allocation is eliminated.

use anyhow::Result;
use std::borrow::Cow;
use std::fs::File;
use std::io::{BufReader, Read};
use std::path::Path;

use super::crc;

const MAGIC: u32 = 0x43434857; // "CCHW"

/// CCH weights - stores weights and relaxed middle nodes for UP and DOWN edges.
/// The middle arrays are the post-triangle-relaxation middles — these are the
/// correct middles for path unpacking (the topology's middles are from contraction
/// and may be suboptimal).
///
/// Fields are `Cow<'static, [u32]>` so they can either own a `Vec<u32>`
/// (legacy / writer / construction sites) or borrow a slice straight
/// from a leaked-mmap `&'static [u32]` (zero-copy server load — #147).
/// All `&self.up` access patterns deref to `&[u32]` regardless of variant.
#[derive(Debug, Clone)]
pub struct CchWeights {
    pub up: Cow<'static, [u32]>,
    pub down: Cow<'static, [u32]>,
    /// Relaxed middle nodes for UP shortcuts (empty if not available — use topo middles)
    pub up_middle: Cow<'static, [u32]>,
    /// Relaxed middle nodes for DOWN shortcuts (empty if not available — use topo middles)
    pub down_middle: Cow<'static, [u32]>,
}

pub struct CchWeightsFile;

impl CchWeightsFile {
    pub fn read<P: AsRef<Path>>(path: P) -> Result<CchWeights> {
        let file = File::open(path.as_ref())?;
        let file_len = file.metadata()?.len() as usize;
        Self::read_from_reader(BufReader::new(file), file_len)
    }

    /// Read directly from an in-memory byte slice (e.g. an mmap-backed
    /// section of a `butterfly.dat` container). Allocating path —
    /// produces owning `Cow::Owned` Vecs.
    pub fn read_from_bytes(bytes: &[u8]) -> Result<CchWeights> {
        Self::read_from_reader(std::io::Cursor::new(bytes), bytes.len())
    }

    /// Zero-copy read over a `'static` byte slice. Returns `CchWeights`
    /// whose fields are `Cow::Borrowed` slices into the input bytes.
    /// The caller is responsible for keeping `bytes` valid for `'static`
    /// (typically by leaking the `Arc<Mmap>` once at server boot — see
    /// `ServerState::load_from_container`).
    ///
    /// CRC is verified before returning. Section start MUST be 4-byte
    /// aligned (the container writer ensures 8-byte alignment for every
    /// section, so this always holds for `.butterfly` files).
    pub fn read_from_bytes_zero_copy(bytes: &'static [u8]) -> Result<CchWeights> {
        // ----- Header (32 bytes) -----
        anyhow::ensure!(
            bytes.len() >= 32,
            "cch.weights too short for header: {} bytes",
            bytes.len()
        );
        let header = &bytes[..32];
        let magic = u32::from_le_bytes(header[0..4].try_into().unwrap());
        anyhow::ensure!(
            magic == MAGIC,
            "Invalid magic: expected 0x{:08X}, got 0x{:08X}",
            MAGIC,
            magic
        );
        let n_up = u64::from_le_bytes(header[8..16].try_into().unwrap()) as usize;
        let n_down = u64::from_le_bytes(header[16..24].try_into().unwrap()) as usize;

        // ----- Layout: header(32) | up(4*n_up) | down(4*n_down) |
        //               [v2: up_middle(4*n_up) | down_middle(4*n_down)] |
        //               footer(16)
        let expected_v1_len = 32 + 4 * (n_up + n_down) + 16;
        let expected_v2_len = expected_v1_len + 4 * (n_up + n_down);
        let is_v2 = match bytes.len() {
            n if n == expected_v1_len => false,
            n if n == expected_v2_len => true,
            n => anyhow::bail!(
                "Invalid cch.weights size: got {}, expected {} (v1) or {} (v2)",
                n,
                expected_v1_len,
                expected_v2_len
            ),
        };

        let up_off = 32;
        let up_end = up_off + 4 * n_up;
        let down_off = up_end;
        let down_end = down_off + 4 * n_down;

        let up: &'static [u32] = bytemuck::cast_slice(&bytes[up_off..up_end]);
        let down: &'static [u32] = bytemuck::cast_slice(&bytes[down_off..down_end]);

        let (up_middle, down_middle, body_end) = if is_v2 {
            let upm_off = down_end;
            let upm_end = upm_off + 4 * n_up;
            let dnm_off = upm_end;
            let dnm_end = dnm_off + 4 * n_down;
            let upm: &'static [u32] = bytemuck::cast_slice(&bytes[upm_off..upm_end]);
            let dnm: &'static [u32] = bytemuck::cast_slice(&bytes[dnm_off..dnm_end]);
            (Cow::Borrowed(upm), Cow::Borrowed(dnm), dnm_end)
        } else {
            (Cow::Borrowed(&[][..]), Cow::Borrowed(&[][..]), down_end)
        };

        // ----- CRC: covers everything before the 16-byte footer -----
        let body = &bytes[..body_end];
        let computed_crc = {
            let mut d = crc::Digest::new();
            d.update(body);
            d.finalize()
        };
        let footer = &bytes[body_end..body_end + 16];
        let stored_crc = u64::from_le_bytes(footer[0..8].try_into().unwrap());
        anyhow::ensure!(
            computed_crc == stored_crc,
            "CRC64 mismatch in cch.weights: computed 0x{:016X}, stored 0x{:016X}",
            computed_crc,
            stored_crc
        );

        Ok(CchWeights {
            up: Cow::Borrowed(up),
            down: Cow::Borrowed(down),
            up_middle,
            down_middle,
        })
    }

    fn read_from_reader<R: Read>(mut reader: R, file_len: usize) -> Result<CchWeights> {
        let mut crc_digest = crc::Digest::new();

        // Read header (32 bytes)
        // magic(4) + reserved(4) + n_up(8) + n_down(8) + reserved(8) = 32
        let mut header = [0u8; 32];
        reader.read_exact(&mut header)?;
        crc_digest.update(&header);

        let magic = u32::from_le_bytes([header[0], header[1], header[2], header[3]]);
        if magic != MAGIC {
            anyhow::bail!(
                "Invalid magic: expected 0x{:08X}, got 0x{:08X}",
                MAGIC,
                magic
            );
        }

        let n_up = u64::from_le_bytes([
            header[8], header[9], header[10], header[11], header[12], header[13], header[14],
            header[15],
        ]) as usize;
        let n_down = u64::from_le_bytes([
            header[16], header[17], header[18], header[19], header[20], header[21], header[22],
            header[23],
        ]) as usize;

        // Read up weights
        let mut up = Vec::with_capacity(n_up);
        for _ in 0..n_up {
            let mut buf = [0u8; 4];
            reader.read_exact(&mut buf)?;
            crc_digest.update(&buf);
            up.push(u32::from_le_bytes(buf));
        }

        // Read down weights
        let mut down = Vec::with_capacity(n_down);
        for _ in 0..n_down {
            let mut buf = [0u8; 4];
            reader.read_exact(&mut buf)?;
            crc_digest.update(&buf);
            down.push(u32::from_le_bytes(buf));
        }

        let expected_v1_len = 32 + 4 * (n_up + n_down) + 16;
        let expected_v2_len = expected_v1_len + 4 * (n_up + n_down);

        let (up_middle, down_middle): (Vec<u32>, Vec<u32>) = match file_len {
            len if len == expected_v1_len => (Vec::new(), Vec::new()),
            len if len == expected_v2_len => {
                // Read relaxed middle arrays (v2: after weights, before CRC)
                let mut up_middle = Vec::with_capacity(n_up);
                for _ in 0..n_up {
                    let mut buf = [0u8; 4];
                    reader.read_exact(&mut buf)?;
                    crc_digest.update(&buf);
                    up_middle.push(u32::from_le_bytes(buf));
                }
                let mut down_middle = Vec::with_capacity(n_down);
                for _ in 0..n_down {
                    let mut buf = [0u8; 4];
                    reader.read_exact(&mut buf)?;
                    crc_digest.update(&buf);
                    down_middle.push(u32::from_le_bytes(buf));
                }
                (up_middle, down_middle)
            }
            len => anyhow::bail!(
                "Invalid cch.weights size: got {}, expected {} (v1) or {} (v2)",
                len,
                expected_v1_len,
                expected_v2_len
            ),
        };

        // Verify CRC64
        let computed_crc = crc_digest.finalize();
        let mut footer = [0u8; 16];
        reader.read_exact(&mut footer)?;
        let stored_crc = u64::from_le_bytes(footer[0..8].try_into().unwrap());
        anyhow::ensure!(
            computed_crc == stored_crc,
            "CRC64 mismatch in cch.weights: computed 0x{:016X}, stored 0x{:016X}",
            computed_crc,
            stored_crc
        );

        Ok(CchWeights {
            up: Cow::Owned(up),
            down: Cow::Owned(down),
            up_middle: Cow::Owned(up_middle),
            down_middle: Cow::Owned(down_middle),
        })
    }
}
